mapper.select:
SELECT id, user_id AS userId, username, module, action, method, params, ip, cost_ms AS costMs, status, error_msg AS errorMsg, create_time AS createTime
FROM sys_log

  AND username LIKE CONCAT('%',#{username},'%')
  AND module = #{module}
  AND status = #{status}
  AND create_time >= #{start}
  AND create_time <= #{end}

ORDER BY id DESC
